WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('binomial-coefficient','Math & Recursion','function','go','Binomial Coefficient','Compute C(n,k), the number of ways to choose k elements from n elements. Return 0 if k is out of range.','Binomial','int',ARRAY['int','int']::text[],ARRAY['Use recurrence: C(n,k) = C(n-1,k-1) + C(n-1,k).','Base cases: C(n,0)=1, C(n,n)=1, C(n,k)=0 if k<0 or k>n.','Use memoisation or Pascal triangle for efficiency.'],2,100,ARRAY['math','recursion','combinatorics','medium'],true,'MANUAL:binomial-coefficient',$$Compute binomial coefficient C(n,k).$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[5,2]'::jsonb,'10',false,1),('[10,3]'::jsonb,'120',false,2),('[4,4]'::jsonb,'1',false,3),('[5,6]'::jsonb,'0',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('armstrong-number','Math & Recursion','function','go','Armstrong Number','An Armstrong number is an n-digit number equal to the sum of its digits each raised to power n. Return true if the given integer is an Armstrong number.','IsArmstrong','bool',ARRAY['int']::text[],ARRAY['Count the number of digits first.','Extract each digit, raise it to the power of digit count, and sum.','153 = 1^3 + 5^3 + 3^3 is a classic example.'],1,60,ARRAY['math','numbers','basic'],true,'MANUAL:armstrong-number',$$Check whether a number is an Armstrong number.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
