WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('next-greater-element','Data Structures','function','go','Next Greater Element','Given an integer slice, return a slice where result[i] is the next greater element to the right of nums[i], or -1 if none exists.','NextGreaterElement','[]int',ARRAY['[]int']::text[],ARRAY['Use a stack to track indices waiting for a greater element.','Iterate left to right; while current > nums[stack.top], pop and set result.','Elements without a greater neighbour stay -1.'],2,100,ARRAY['arrays','stack','monotonic','medium'],true,'MANUAL:next-greater-element',$$Find the next greater element for each position.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[4,1,2,1,3]]'::jsonb,'[-1,2,3,3,-1]',false,1),('[[1,2,3,4]]'::jsonb,'[2,3,4,-1]',false,2),('[[4,3,2,1]]'::jsonb,'[-1,-1,-1,-1]',false,3),('[[]]'::jsonb,'[]',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('daily-temperatures','Data Structures','function','go','Daily Temperatures','Given a slice of daily temperatures, for each day return how many days to wait until a warmer temperature. If none, return 0.','DailyTemperatures','[]int',ARRAY['[]int']::text[],ARRAY['Use a stack storing indices of days with decreasing temperatures.','When a warmer temperature is found, pop from stack and compute days difference.','If stack is non-empty at the end, remaining days get 0.'],3,130,ARRAY['arrays','stack','monotonic','medium'],true,'MANUAL:daily-temperatures',$$Compute days until warmer temperature for each day.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[73,74,75,71,69,72,76,73]]'::jsonb,'[1,1,4,2,1,1,0,0]',false,1),('[[30,40,50,60]]'::jsonb,'[1,1,1,0]',false,2),('[[90,80,70,60]]'::jsonb,'[0,0,0,0]',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('max-sliding-window','Data Structures','function','go','Sliding Window Maximum','Given an integer slice and window size k, return the maximum element in every contiguous subarray of size k.','MaxSlidingWindow','[]int',ARRAY['[]int','int']::text[],ARRAY['Use a deque storing indices; maintain decreasing values.','Remove indices outside the window from the front.','The front of the deque is always the max of the current window.'],3,150,ARRAY['arrays','deque','sliding-window','medium'],true,'MANUAL:max-sliding-window',$$Find maximum in every sliding window of size k.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
