WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('merge-sorted','Sorting & Searching','function','go','Merge Sorted Arrays','Merge two sorted integer slices into one sorted slice.','MergeSorted','[]int',ARRAY['[]int','[]int']::text[],ARRAY['Use two pointers, one for each slice.','Compare elements at both pointers and append the smaller one.','If one list is exhausted, append the rest of the other list.'],1,60,ARRAY['arrays','sorting','two-pointers','basic'],true,'MANUAL:merge-sorted',$$Merge two sorted arrays into one sorted result.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[1,2,3],[2,5,6]]'::jsonb,'[1,2,2,3,5,6]',false,1),('[[],[1]]'::jsonb,'[1]',false,2),('[[1,1,1],[1,1,1]]'::jsonb,'[1,1,1,1,1,1]',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('binary-search','Sorting & Searching','function','go','Binary Search','Given a sorted integer slice and a target value, return the index of target. If not found, return -1.','BinarySearch','int',ARRAY['[]int','int']::text[],ARRAY['Maintain left and right pointers.','Mid = left + (right-left)/2 to avoid overflow.','If nums[mid] < target, search right half; else search left half.'],1,50,ARRAY['searching','binary-search','basic'],true,'MANUAL:binary-search',$$Binary search a target in a sorted array.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[-1,0,3,5,9,12],9]'::jsonb,'4',false,1),('[[-1,0,3,5,9,12],2]'::jsonb,'-1',false,2),('[[1],1]'::jsonb,'0',false,3),('[[],5]'::jsonb,'-1',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('find-peak','Sorting & Searching','function','go','Find Peak Element','A peak element is strictly greater than its neighbours. Return the index of any peak element.','FindPeak','int',ARRAY['[]int']::text[],ARRAY['Use binary search: if mid > mid+1, peak in left half; else right half.','The array may have multiple peaks; return any one.','Edge case: single element is a peak (index 0).'],2,90,ARRAY['searching','binary-search','peak','medium'],true,'MANUAL:find-peak',$$Find any peak element in an array.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[1,2,3,1]]'::jsonb,'2',false,1),('[[1,2,1,3,5,6,4]]'::jsonb,'5',false,2),('[[1]]'::jsonb,'0',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('quick-sort','Sorting & Searching','function','go','Quick Sort','Implement quick sort to sort an integer slice in ascending order. Return the sorted slice.','QuickSort','[]int',ARRAY['[]int']::text[],ARRAY['Choose a pivot (e.g., last element).','Partition: elements < pivot on left, > pivot on right.','Recursively sort the left and right partitions.'],2,100,ARRAY['sorting','divide-conquer','medium'],true,'MANUAL:quick-sort',$$Implement quick sort algorithm.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[3,6,1,8,2,5]]'::jsonb,'[1,2,3,5,6,8]',false,1),('[[1]]'::jsonb,'[1]',false,2),('[[]]'::jsonb,'[]',true,3),('[[5,4,3,2,1]]'::jsonb,'[1,2,3,4,5]',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('first-bad-version','Sorting & Searching','function','go','First Bad Version','An API isBadVersion(n int) bool is provided. Find the first bad version in the range 1..n, minimising API calls.','FirstBadVersion','int',ARRAY['int']::text[],ARRAY['Classic binary search variant.','If mid is bad, search left; if not, search right.','Return the left pointer when loop ends.'],2,80,ARRAY['searching','binary-search','medium'],true,'MANUAL:first-bad-version',$$Find the first bad version using binary search.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[5]'::jsonb,'4',false,1),('[1]'::jsonb,'1',false,2),('[10]'::jsonb,'7',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('find-kth-smallest','Sorting & Searching','function','go','Kth Smallest Element','Given an unsorted integer slice, return the kth smallest element (1-indexed). You may modify the input.','KthSmallest','int',ARRAY['[]int','int']::text[],ARRAY['Use quick select: partition like quicksort, then recurse on the relevant half.','If pivot index == k-1, return it.','Average O(n) time, worst-case O(n^2).'],3,130,ARRAY['searching','quickselect','divide-conquer','medium'],true,'MANUAL:find-kth-smallest',$$Find kth smallest element using quick select.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
