WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('contains-duplicate','Hash Maps & Sets','function','go','Contains Duplicate','Return true if any value appears at least twice in the slice.','ContainsDuplicate','bool',ARRAY['[]int']::text[],ARRAY['Use a set (map[int]bool) to track seen values.','If a value is already in the set, return true.','If loop completes, return false.'],1,40,ARRAY['hashmap','arrays','basic'],true,'MANUAL:contains-duplicate',$$Check if any value appears more than once.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
