WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('intersection-of-two','Hash Maps & Sets','function','go','Intersection of Two Arrays','Return the intersection of two integer slices (each element is unique).','Intersection','[]int',ARRAY['[]int','[]int']::text[],ARRAY['Store elements of the first slice in a set.','Iterate the second slice; if element is in the set, add to result and remove from set.','Return the result slice (unique values only).'],1,60,ARRAY['hashmap','sets','arrays','basic'],true,'MANUAL:intersection-of-two',$$Find the intersection of two arrays.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[1,2,2,1],[2,2]]'::jsonb,'[2]',false,1),('[[4,9,5],[9,4,9,8,4]]'::jsonb,'[9,4]',false,2),('[[1,2,3],[4,5,6]]'::jsonb,'[]',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('group-anagrams','Hash Maps & Sets','function','go','Group Anagrams','Given a slice of strings, group anagrams together (order within groups does not matter).','GroupAnagrams','[][]string',ARRAY['[]string']::text[],ARRAY['Sort each string to use as the map key.','Alternatively, use a character frequency count as key.','Append each string to its group in the map.'],2,110,ARRAY['hashmap','strings','sorting','medium'],true,'MANUAL:group-anagrams',$$Group strings that are anagrams of each other.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[["eat","tea","tan","ate","nat","bat"]]'::jsonb,'[["eat","tea","ate"],["tan","nat"],["bat"]]',false,1),('[[""]]'::jsonb,'[[""]]',false,2),('[["a"]]'::jsonb,'[["a"]]',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('longest-consecutive','Hash Maps & Sets','function','go','Longest Consecutive Sequence','Given an unsorted integer slice, return the length of the longest consecutive elements sequence. Must run in O(n).','LongestConsecutive','int',ARRAY['[]int']::text[],ARRAY['Add all numbers to a set.','For each number, check if num-1 is NOT in the set (start of a sequence).','Count consecutive numbers from each start and track the maximum length.'],3,140,ARRAY['hashmap','sets','arrays','medium'],true,'MANUAL:longest-consecutive',$$Find the length of the longest consecutive sequence.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
