WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('subarray-sum-equals','Hash Maps & Sets','function','go','Subarray Sum Equals K','Given an integer slice and target k, return the number of contiguous subarrays that sum to k.','SubarraySum','int',ARRAY['[]int','int']::text[],ARRAY['Use prefix sum and a map[prefixSum]count.','For each element, compute running sum. Check if sum-k exists in map; if so, add its count.','Update the map with the current sum.'],3,130,ARRAY['hashmap','prefix-sum','arrays','medium'],true,'MANUAL:subarray-sum-equals',$$Count subarrays whose sum equals k.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[1,1,1],2]'::jsonb,'2',false,1),('[[1,2,3],3]'::jsonb,'2',false,2),('[[1],0]'::jsonb,'0',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('majority-element','Hash Maps & Sets','function','go','Majority Element','Find the element that appears more than n/2 times in a slice. Assume the majority element always exists.','MajorityElement','int',ARRAY['[]int']::text[],ARRAY['Use Boyer-Moore voting algorithm: O(n) time, O(1) space.','Maintain a candidate and a count; cancel pairs of different elements.','The remaining candidate is the majority element.'],2,80,ARRAY['hashmap','voting','arrays','medium'],true,'MANUAL:majority-element',$$Find the element appearing more than n/2 times.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
