WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('missing-number','Hash Maps & Sets','function','go','Missing Number','Given a slice of n distinct numbers from 0..n, return the one missing from the range.','MissingNumber','int',ARRAY['[]int']::text[],ARRAY['Compute expected sum = n*(n+1)/2.','Subtract actual sum from expected sum.','The difference is the missing number.'],1,50,ARRAY['hashmap','math','arrays','basic'],true,'MANUAL:missing-number',$$Find the missing number in a sequence.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
