WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('counter','Concurrency','function','go','Concurrent Counter','Increment a shared counter n times using goroutines. Return the final counter value. Use sync.Mutex for safety.','ConcurrentCounter','int',ARRAY['int']::text[],ARRAY['Use a sync.Mutex to protect the shared counter.','Launch n goroutines, each incrementing the counter by 1.','Use a sync.WaitGroup to wait for all goroutines to finish.'],3,140,ARRAY['goroutines','mutex','concurrency','medium'],true,'MANUAL:counter',$$Implement a concurrent counter with mutex.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[100]'::jsonb,'100',false,1),('[1000]'::jsonb,'1000',false,2),('[1]'::jsonb,'1',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('producer-consumer','Concurrency','function','go','Producer-Consumer','Implement a producer-consumer pattern. Given a buffer size, produce n items and consume them. Return the count of successfully consumed items.','ProducerConsumer','int',ARRAY['int','int']::text[],ARRAY['Use a buffered channel as the shared queue.','Producer sends numbers into the channel; consumer receives them.','Use a done channel or WaitGroup to signal completion.'],4,180,ARRAY['channels','goroutines','concurrency','hard'],true,'MANUAL:producer-consumer',$$Implement producer-consumer with channels.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[5,10]'::jsonb,'10',false,1),('[1,5]'::jsonb,'5',false,2),('[10,100]'::jsonb,'100',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('fan-in','Concurrency','function','go','Fan-In Merge','Merge multiple input channels into a single output channel using fan-in pattern. Return all values received from all channels in order.','FanIn','[]int',ARRAY['int','int']::text[],ARRAY['Launch a goroutine for each input channel that forwards to the output.','Use a WaitGroup to detect when all source channels are exhausted.','Close the merged channel after all sources are done.'],4,180,ARRAY['channels','goroutines','fan-in','hard'],true,'MANUAL:fan-in',$$Merge values from multiple channels into one.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
