WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('worker-pool','Concurrency','function','go','Worker Pool','Given numJobs and numWorkers, dispatch jobs to workers and collect results. Each job i returns i*2. Return the sum of all results.','WorkerPool','int',ARRAY['int','int']::text[],ARRAY['Create a jobs channel and a results channel.','Start numWorkers goroutines that read from jobs and write to results.','Send numJobs to jobs, close it, then collect numJobs results.'],3,160,ARRAY['goroutines','channels','worker-pool','medium'],true,'MANUAL:worker-pool',$$Implement a worker pool pattern.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
