WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('coin-change','Dynamic Programming','function','go','Coin Change','Given a slice of coin denominations and a target amount, return the minimum number of coins to make that amount. Return -1 if impossible.','CoinChange','int',ARRAY['[]int','int']::text[],ARRAY['DP[i] = minimum coins to make amount i. Initialise DP[0]=0, rest=max.','For each coin, DP[i] = min(DP[i], DP[i-coin]+1).','If DP[amount] is still max, return -1.'],3,150,ARRAY['dp','optimisation','medium'],true,'MANUAL:coin-change',$$Minimum coins to make a target amount.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[1,2,5],11]'::jsonb,'3',false,1),('[[2],3]'::jsonb,'-1',false,2),('[[1],0]'::jsonb,'0',false,3),('[[1,3,4,5],7]'::jsonb,'2',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('longest-increasing-subseq','Dynamic Programming','function','go','Longest Increasing Subsequence','Given an integer slice, return the length of the longest strictly increasing subsequence.','LIS','int',ARRAY['[]int']::text[],ARRAY['DP[i] = LIS ending at index i. Initialise all to 1.','For each i, check all j < i; if nums[j] < nums[i], DP[i] = max(DP[i], DP[j]+1).','Return max of DP array (or 0 for empty input).'],3,140,ARRAY['dp','subsequence','medium'],true,'MANUAL:longest-increasing-subseq',$$Length of the longest increasing subsequence.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[10,9,2,5,3,7,101,18]]'::jsonb,'4',false,1),('[[0,1,0,3,2,3]]'::jsonb,'4',false,2),('[[7,7,7,7]]'::jsonb,'1',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('climbing-stairs','Dynamic Programming','function','go','Climbing Stairs','You climb a staircase of n steps. Each time you can take 1 or 2 steps. Return the number of distinct ways to reach the top.','ClimbingStairs','int',ARRAY['int']::text[],ARRAY['DP[i] = ways to reach step i. DP[1]=1, DP[2]=2.','DP[i] = DP[i-1] + DP[i-2] (this is Fibonacci-like).','Base cases: n=0 yields 0, n=1 yields 1, n=2 yields 2.'],1,50,ARRAY['dp','fibonacci','basic'],true,'MANUAL:climbing-stairs',$$Count ways to climb n steps (1 or 2 steps at a time).$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[2]'::jsonb,'2',false,1),('[3]'::jsonb,'3',false,2),('[5]'::jsonb,'8',false,3),('[1]'::jsonb,'1',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('edit-distance','Dynamic Programming','function','go','Edit Distance','Return the minimum number of operations (insert, delete, replace) to convert string word1 into string word2.','EditDistance','int',ARRAY['string','string']::text[],ARRAY['DP[i][j] = edit distance between word1[0:i] and word2[0:j].','If characters match: DP[i][j] = DP[i-1][j-1].','Else: DP[i][j] = 1 + min(insert, delete, replace).'],4,200,ARRAY['dp','strings','hard'],true,'MANUAL:edit-distance',$$Minimum edit distance between two strings.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('["horse","ros"]'::jsonb,'3',false,1),('["intention","execution"]'::jsonb,'5',false,2),('["","a"]'::jsonb,'1',false,3),('["abc","abc"]'::jsonb,'0',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('knapsack','Dynamic Programming','function','go','0/1 Knapsack','Given a slice of item weights and corresponding values, and a knapsack capacity, return the maximum total value possible.','Knapsack','int',ARRAY['[]int','[]int','int']::text[],ARRAY['DP[i][w] = max value using first i items with capacity w.','For each item, either skip it (DP[i-1][w]) or take it (DP[i-1][w-weight[i]] + value[i]).','Return DP[n][capacity].'],3,160,ARRAY['dp','knapsack','optimisation','medium'],true,'MANUAL:knapsack',$$Solve the 0/1 knapsack problem.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[1,2,3],[6,10,12],5]'::jsonb,'22',false,1),('[[2,3,4],[3,4,5],5]'::jsonb,'7',false,2),('[[1,2,3],[10,15,40],6]'::jsonb,'50',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('max-product-subarray','Dynamic Programming','function','go','Maximum Product Subarray','Given an integer slice, find the contiguous subarray with the largest product and return the product.','MaxProductSubarray','int',ARRAY['[]int']::text[],ARRAY['Track both max and min product ending at each index (due to negative numbers).','If current number is negative, swap max and min before multiplying.','Update the global maximum after each step.'],3,150,ARRAY['dp','arrays','medium'],true,'MANUAL:max-product-subarray',$$Maximum product of a contiguous subarray.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[2,3,-2,4]]'::jsonb,'6',false,1),('[[-2,0,-1]]'::jsonb,'0',false,2),('[[-2,3,-4]]'::jsonb,'24',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('palindrome-partitioning','Dynamic Programming','function','go','Palindrome Partitioning','Given a string, partition it into substrings such that every substring is a palindrome. Return ALL possible palindrome partitions.','PalindromePartition','[][]string',ARRAY['string']::text[],ARRAY['Use backtracking + DP for palindrome checks.','Precompute isPalindrome[i][j] for all substrings via DP.','At each step, extend the current partition with a palindrome substring.'],4,190,ARRAY['dp','backtracking','strings','hard'],true,'MANUAL:palindrome-partitioning',$$Return all palindrome partitions of a string.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('["aab"]'::jsonb,'[["a","a","b"],["aa","b"]]',false,1),('["a"]'::jsonb,'[["a"]]',false,2),('[""]'::jsonb,'[[""]]',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('word-break','Dynamic Programming','function','go','Word Break','Given a string and a dictionary of strings ([]string), return true if the string can be segmented into dictionary words.','WordBreak','bool',ARRAY['string','[]string']::text[],ARRAY['DP[i] = true if s[0:i] can be segmented. Initialise DP[0]=true.','For each i, check all j < i: if DP[j] and s[j:i] is in wordDict, set DP[i]=true.','Use a map for O(1) dictionary lookups.'],3,150,ARRAY['dp','strings','medium'],true,'MANUAL:word-break',$$Check if a string can be segmented into dictionary words.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
