WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('hamming-weight','Bit Manipulation','function','go','Hamming Weight','Return the number of 1 bits (set bits) in the binary representation of a non-negative integer.','HammingWeight','int',ARRAY['int']::text[],ARRAY['Use n & (n-1) to clear the lowest set bit repeatedly.','Count how many times you can do this until n becomes 0.','Alternatively, shift right and check LSB, but n & (n-1) is more efficient.'],1,50,ARRAY['bits','basic'],true,'MANUAL:hamming-weight',$$Count set bits (1s) in binary representation.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[11]'::jsonb,'3',false,1),('[128]'::jsonb,'1',false,2),('[2147483645]'::jsonb,'30',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('single-number','Bit Manipulation','function','go','Single Number','Given a slice where every element appears twice except one, find the element that appears once.','SingleNumber','int',ARRAY['[]int']::text[],ARRAY['XOR all numbers together: a XOR a = 0, a XOR 0 = a.','Duplicate pairs cancel out.','The remaining value is the single number.'],1,50,ARRAY['bits','xor','arrays','basic'],true,'MANUAL:single-number',$$Find the element that appears once when all others appear twice.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[2,2,1]]'::jsonb,'1',false,1),('[[4,1,2,1,2]]'::jsonb,'4',false,2),('[[1]]'::jsonb,'1',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('power-of-two','Bit Manipulation','function','go','Power of Two','Return true if n is a power of two, false otherwise.','PowerOfTwo','bool',ARRAY['int']::text[],ARRAY['A power of two has exactly one set bit.','Use n > 0 && (n & (n-1)) == 0 to check.','Edge cases: n=0 is false, n=1 is true (2^0).'],1,40,ARRAY['bits','math','basic'],true,'MANUAL:power-of-two',$$Check if a number is a power of two.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[1]'::jsonb,'true',false,1),('[16]'::jsonb,'true',false,2),('[218]'::jsonb,'false',false,3),('[0]'::jsonb,'false',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('bit-reverse','Bit Manipulation','function','go','Reverse Bits','Reverse the bits of a given 32-bit unsigned integer and return the result.','ReverseBits','int',ARRAY['int']::text[],ARRAY['Iterate through all 32 bits of the input.','Shift result left, add the LSB of n, then shift n right.','Be careful with sign extension; treat as uint32 if needed.'],2,100,ARRAY['bits','medium'],true,'MANUAL:bit-reverse',$$Reverse the bits of a 32-bit unsigned integer.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[43261596]'::jsonb,'964176192',false,1),('[4294967293]'::jsonb,'3221225471',false,2),('[0]'::jsonb,'0',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('find-difference','Bit Manipulation','function','go','Find the Difference','Given two strings s and t where t is generated by randomly shuffling s and adding one extra character, find the added character.','FindTheDifference','byte',ARRAY['string','string']::text[],ARRAY['XOR all bytes from both strings together.','Every character appearing in both will XOR to 0.','The remaining byte is the extra character.'],1,50,ARRAY['bits','xor','strings','basic'],true,'MANUAL:find-difference',$$Find the character added to one string vs another.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('["abcd","abcde"]'::jsonb,'"e"',false,1),('["","y"]'::jsonb,'"y"',false,2),('["a","aa"]'::jsonb,'"a"',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('has-alternating-bits','Bit Manipulation','function','go','Alternating Bits','Return true if the binary representation of n has alternating bits (every pair of adjacent bits differ).','HasAlternatingBits','bool',ARRAY['int']::text[],ARRAY['Compute n XOR (n>>1). If the result has all bits set to 1, the original has alternating bits.','Check if (n XOR n>>1) is a power of two minus 1.','For example: 5 (101) -> 101 XOR 010 = 111 (which is 2^3-1).'],1,60,ARRAY['bits','basic'],true,'MANUAL:has-alternating-bits',$$Check if a number has alternating bits.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[5]'::jsonb,'true',false,1),('[7]'::jsonb,'false',false,2),('[11]'::jsonb,'false',false,3),('[0]'::jsonb,'true',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('subset-xor-sum','Bit Manipulation','function','go','XOR-Based Subset Sum','Given a slice of integers, return the sum of XORs of all subsets.','SubsetXORSum','int',ARRAY['[]int']::text[],ARRAY['Bitwise OR of all elements, then left shift by n-1 bits.','Each bit contributes 2^(n-1) * (that bit set in OR).','OR all elements to find which bits appear at least once.'],2,100,ARRAY['bits','xor','math','medium'],true,'MANUAL:subset-xor-sum',$$Sum of XOR totals of all subsets.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[1,3]]'::jsonb,'6',false,1),('[[5,1,6]]'::jsonb,'28',false,2),('[[1,2,3]]'::jsonb,'12',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

