WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('max-depth-bt','Trees & Graphs','function','go','Maximum Depth of Binary Tree','Given a binary tree represented as a slice in level order (with -1 as null), return its maximum depth.','MaxDepthBT','int',ARRAY['[]int']::text[],ARRAY['The root is at index 0. Children of node i are at 2i+1 and 2i+2.','Skip null nodes (-1) when computing children.','Use recursion: depth = 1 + max(depth(left), depth(right)).'],2,100,ARRAY['trees','binary-tree','recursion','medium'],true,'MANUAL:max-depth-bt',$$Find the maximum depth of a binary tree.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
