WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('inorder-traversal','Trees & Graphs','function','go','Inorder Traversal','Given a binary tree represented as a level-order slice, return the inorder traversal as a slice.','InorderTraversal','[]int',ARRAY['[]int']::text[],ARRAY['Inorder visits: left, root, right.','Use a stack for iterative traversal or recursion.','Null nodes (-1) are skipped.'],2,80,ARRAY['trees','binary-tree','traversal','medium'],true,'MANUAL:inorder-traversal',$$Return the inorder traversal of a binary tree.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
