WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('has-path-sum','Trees & Graphs','function','go','Path Sum','Given a binary tree level-order slice and a target sum, return true if there is a root-to-leaf path summing to target.','HasPathSum','bool',ARRAY['[]int','int']::text[],ARRAY['Subtract current node value from remaining sum on each recursion step.','If at a leaf (no children) and remaining sum is 0, return true.','Null nodes are skipped.'],2,100,ARRAY['trees','binary-tree','dfs','medium'],true,'MANUAL:has-path-sum',$$Check if there is a root-to-leaf path with a given sum.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
