WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('is-graph-bipartite','Trees & Graphs','function','go','Graph Bipartite','Given an adjacency list ([][]int), return true if the graph is bipartite.','IsBipartite','bool',ARRAY['[][]int']::text[],ARRAY['Two-color algorithm: assign 0 (uncolored), 1 (red), -1 (blue).','Use BFS: for each uncolored node, start BFS coloring neighbours opposite.','If a neighbour has the same color as current, return false.'],3,150,ARRAY['graphs','bfs','bipartite','medium'],true,'MANUAL:is-graph-bipartite',$$Check if a graph is bipartite.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
