WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('number-of-islands','Trees & Graphs','function','go','Number of Islands','Given a 2D grid (][]int) of 1s (land) and 0s (water), return the number of islands (connected 1s orthogonally).','NumIslands','int',ARRAY['[][]int']::text[],ARRAY['Iterate each cell; when land (1) is found, increment count and DFS/BFS to mark all connected land.','Mark visited land as 0 or use a visited set.','Use a closure or helper function for DFS traversal in 4 directions.'],3,140,ARRAY['graphs','dfs','bfs','grid','medium'],true,'MANUAL:number-of-islands',$$Count the number of islands in a 2D grid.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
