WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('is-valid-bst','Trees & Graphs','function','go','Validate Binary Search Tree','Given a level-order tree slice, return true if it is a valid BST (all left < root < right recursively).','IsValidBST','bool',ARRAY['[]int']::text[],ARRAY['Track min/max allowed value as you recurse.','Left subtree must be within (min, root.val) and right within (root.val, max).','Use -inf and +inf for the root range limits.'],3,130,ARRAY['trees','bst','validation','medium'],true,'MANUAL:is-valid-bst',$$Validate a binary search tree.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
