WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('has-cycle','Linked Lists','function','go','Linked List Cycle','Given a slice of values and a "cycle position" pos, build a linked list. If pos >= 0, the tail connects to the node at index pos. Return true if a cycle exists.','HasCycle','bool',ARRAY['[]int','int']::text[],ARRAY['Floyd tortoise and hare algorithm: slow moves 1 step, fast moves 2 steps.','If fast and slow meet, a cycle exists.','Build the list first, then connect the tail to the node at position pos (if pos >= 0).'],3,120,ARRAY['linked-list','cycle','two-pointers','medium'],true,'MANUAL:has-cycle',$$Detect if a linked list has a cycle.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[3,2,0,-4],1]'::jsonb,'true',false,1),('[[1,2],0]'::jsonb,'true',false,2),('[[1],-1]'::jsonb,'false',false,3),('[[],-1]'::jsonb,'false',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('remove-nth-from-end','Linked Lists','function','go','Remove Nth From End','Given a slice of values and n, build a linked list, remove the nth node from the end, and return the resulting list values.','RemoveNthFromEnd','[]int',ARRAY['[]int','int']::text[],ARRAY['Use two pointers: fast moves n steps ahead, then both move until fast reaches the end.','Slow pointer is at the node before the one to delete.','Handle edge case: removing the head node.'],3,120,ARRAY['linked-list','two-pointers','medium'],true,'MANUAL:remove-nth-from-end',$$Remove the nth node from the end of a linked list.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[1,2,3,4,5],2]'::jsonb,'[1,2,3,5]',false,1),('[[1],1]'::jsonb,'[]',false,2),('[[1,2],1]'::jsonb,'[1]',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('find-middle','Linked Lists','function','go','Middle of Linked List','Given a slice of values, build a linked list and return the middle node(s). If there are two middle nodes, return the second one. Values as slice.','FindMiddle','[]int',ARRAY['[]int']::text[],ARRAY['Tortoise and hare: slow moves 1 step, fast moves 2 steps.','When fast reaches the end, slow is at the middle.','Return the tail of the list starting from the middle node.'],1,50,ARRAY['linked-list','two-pointers','basic'],true,'MANUAL:find-middle',$$Find the middle node of a linked list.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[1,2,3,4,5]]'::jsonb,'[3,4,5]',false,1),('[[1,2,3,4,5,6]]'::jsonb,'[4,5,6]',false,2),('[[1]]'::jsonb,'[1]',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('intersection-of-two-ll','Linked Lists','function','go','Intersection of Two Linked Lists','Given two slices, build two linked lists that intersect at a given node. Return the value of the intersection node, or -1 if they do not intersect.','GetIntersectionNode','int',ARRAY['[]int','[]int','int']::text[],ARRAY['Build list A and B, then attach the tail of each to a common suffix starting at the intersection node.','Align both lists by trimming the longer one.','Traverse both together; the first equal node is the intersection.'],3,130,ARRAY['linked-list','two-pointers','medium'],true,'MANUAL:intersection-of-two-ll',$$Find the intersection node of two linked lists.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[4,1,8,4,5],[5,6,1,8,4,5],2]'::jsonb,'8',false,1),('[[1,9,1,2,4],[3,2,4],3]'::jsonb,'2',false,2),('[[2,6,4],[1,5],-1]'::jsonb,'-1',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

